import type { Storage } from '@kyokuya/react-storage'
import type { KyokuyaSudokuContextData } from '@kyokuya/react-sudoku'
import { useEffect } from 'react'

export function useKyokuyaSudokuContextDataEffect(
  storage: Storage<Partial<KyokuyaSudokuContextData>> | null,
  data: KyokuyaSudokuContextData,
): void {
  const {
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    score,
    attempt,
    puzzle,
    solution,
    activatedCell,
    hintCell,
    gameTick,
  } = data

  useEffect(() => {
    if (storage == null) return
    storage.dump({
      SUDOKU_SIZE_SQRT,
      difficulty,
      radix,
      score,
      attempt,
      puzzle,
      solution,
      activatedCell,
      hintCell,
      gameTick,
    })
  }, [
    storage,
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    score,
    attempt,
    puzzle,
    solution,
    activatedCell,
    hintCell,
    gameTick,
  ])
}

export default useKyokuyaSudokuContextDataEffect
