import { useInterval } from '@guanghechen/react-hooks'
import dayjs from 'dayjs'
import duration from 'dayjs/plugin/duration'
import React, { useCallback, useState } from 'react'
import { useElapsedTime } from '../hooks/useElapsedTime'
import type { GameRunningStatus } from '../types'

dayjs.extend(duration)

export interface ElapsedTimerProps {
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Dayjs time format.
   * @default 'HH:mm:ss'
   */
  format?: string
  /**
   *
   */
  className?: string
  /**
   *
   */
  style?: React.CSSProperties
}

/**
 *
 * @param props
 * @returns
 */
export function ElapsedTimer(props: ElapsedTimerProps): React.ReactElement {
  const { gameStatus: gameState, format = 'HH:mm:ss', className, style } = props
  const [, setTick] = useState<number>(0)
  const refresh = useCallback<() => void>(() => {
    if (gameState === 'running') {
      setTick(v => v + 1)
    }
  }, [gameState])

  const usedTime: number = useElapsedTime(gameState)
  const usedTimeString: string = dayjs.duration(usedTime).format(format)

  // Refresh every 1s.
  useInterval(refresh, 1000)

  return (
    <span className={className} style={style}>
      {usedTimeString}
    </span>
  )
}

ElapsedTimer.displayName = 'ElapsedTimer'
export default ElapsedTimer
